'use client';

import { AlertCircle, Plus } from 'lucide-react';
import { useMemo, useState } from 'react';
import { DataTableShell, EmptyState, LoadingSkeleton, PageHeader } from '@/components/shared';
import { Button } from '@/components/ui/button';
import { Card, CardContent } from '@/components/ui/card';
import { PERMISSIONS } from '@/constants/permissions';
import { ROUTES } from '@/constants/routes';
import { getApiErrorMessage } from '@/lib/api/unwrap';
import { usePermissions } from '@/features/auth/hooks/use-permissions';
import Link from 'next/link';
import { useVehicles } from '../hooks/use-vehicles';
import type { VehicleStatus, VehicleType } from '../types/vehicle.types';
import { VehicleFilters } from './vehicle-filters';
import { vehicleColumns } from './vehicle-table-columns';
import { VehiclesPagination } from './vehicles-pagination';

const DEFAULT_LIMIT = 20;

export function VehiclesListPage() {
  const { hasPermission } = usePermissions();
  const [search, setSearch] = useState('');
  const [vehicleType, setVehicleType] = useState<VehicleType | undefined>();
  const [status, setStatus] = useState<VehicleStatus | undefined>();
  const [availableOnly, setAvailableOnly] = useState(false);
  const [page, setPage] = useState(1);
  const [limit, setLimit] = useState(DEFAULT_LIMIT);

  const queryParams = useMemo(
    () => ({
      page,
      limit,
      search: search.trim() || undefined,
      vehicleType,
      status,
      availableOnly: availableOnly || undefined,
    }),
    [availableOnly, limit, page, search, status, vehicleType],
  );

  const vehiclesQuery = useVehicles(queryParams);
  const vehicles = vehiclesQuery.data?.items ?? [];
  const meta = vehiclesQuery.data?.meta ?? {
    page,
    limit,
    total: 0,
    totalPages: 0,
  };

  const canCreateVehicle = hasPermission(PERMISSIONS.CREATE_VEHICLE);
  const hasActiveFilters = Boolean(search || vehicleType || status || availableOnly);
  const errorMessage = vehiclesQuery.error
    ? getApiErrorMessage(vehiclesQuery.error, 'Unable to load vehicles.')
    : null;

  function resetPageAndRun(action: () => void) {
    setPage(1);
    action();
  }

  function resetFilters() {
    setSearch('');
    setVehicleType(undefined);
    setStatus(undefined);
    setAvailableOnly(false);
    setPage(1);
  }

  return (
    <div className="flex flex-1 flex-col gap-6 p-4 lg:p-6">
      <PageHeader
        title="Vehicles"
        description="Manage fleet units, plate composition, and operational availability."
        actions={
          canCreateVehicle ? (
            <Button type="button" render={<Link href={ROUTES.vehiclesNew} />}>
              <Plus className="size-4" />
              New vehicle
            </Button>
          ) : null
        }
      />

      {vehiclesQuery.isLoading ? (
        <LoadingSkeleton variant="table" />
      ) : errorMessage ? (
        <Card>
          <CardContent>
            <EmptyState
              icon={AlertCircle}
              title="Unable to load vehicles"
              description={errorMessage}
              actionLabel="Retry"
              onAction={() => void vehiclesQuery.refetch()}
              className="border-0 bg-transparent"
            />
          </CardContent>
        </Card>
      ) : (
        <Card>
          <CardContent className="space-y-4">
            <DataTableShell
              columns={vehicleColumns}
              data={vehicles}
              isLoading={vehiclesQuery.isFetching && !vehiclesQuery.isLoading}
              searchPlaceholder="Search code, plate, make…"
              searchValue={search}
              onSearchChange={(value) => resetPageAndRun(() => setSearch(value))}
              emptyTitle={hasActiveFilters ? 'No vehicles match these filters' : 'No vehicles yet'}
              emptyDescription={
                hasActiveFilters
                  ? 'Reset filters or try a different search term.'
                  : 'Vehicles created from the backend API will appear here.'
              }
              footerLabel={null}
              toolbar={
                <VehicleFilters
                  vehicleType={vehicleType}
                  status={status}
                  availableOnly={availableOnly}
                  onVehicleTypeChange={(value) => resetPageAndRun(() => setVehicleType(value))}
                  onStatusChange={(value) => resetPageAndRun(() => setStatus(value))}
                  onAvailableOnlyChange={(value) =>
                    resetPageAndRun(() => {
                      setAvailableOnly(value);
                      if (value) setStatus(undefined);
                    })
                  }
                  onReset={resetFilters}
                />
              }
            />

            <VehiclesPagination
              page={meta.page}
              limit={meta.limit}
              total={meta.total}
              totalPages={meta.totalPages}
              onPageChange={setPage}
              onLimitChange={(value) => {
                setLimit(value);
                setPage(1);
              }}
            />
          </CardContent>
        </Card>
      )}
    </div>
  );
}
