'use client';

import { ShieldAlert } from 'lucide-react';
import { useRouter } from 'next/navigation';
import { EmptyState, PageHeader } from '@/components/shared';
import { Card, CardContent } from '@/components/ui/card';
import { useToast } from '@/components/ui/toast';
import { PERMISSIONS } from '@/constants/permissions';
import { ROUTES } from '@/constants/routes';
import { usePermissions } from '@/features/auth/hooks/use-permissions';
import { getApiErrorMessage } from '@/lib/api/unwrap';
import { useCreateVehicle } from '../hooks/use-vehicles';
import type { CreateVehiclePayload } from '../types/vehicle.types';
import { CreateVehicleForm } from '../forms/create-vehicle-form';

export function CreateVehiclePage() {
  const router = useRouter();
  const { toast } = useToast();
  const { hasPermission } = usePermissions();
  const mutation = useCreateVehicle();
  const canCreate = hasPermission(PERMISSIONS.CREATE_VEHICLE);

  function handleSubmit(payload: CreateVehiclePayload) {
    mutation.mutate(payload, {
      onSuccess: (vehicle) => {
        toast({
          title: 'Vehicle created',
          description: `${vehicle.vehicleCode} is now in the fleet inventory.`,
          variant: 'success',
        });
        router.push(ROUTES.vehicles);
        router.refresh();
      },
      onError: (error) => {
        toast({
          title: 'Vehicle was not created',
          description: getApiErrorMessage(error, 'Check the form and try again.'),
          variant: 'error',
        });
      },
    });
  }

  if (!canCreate) {
    return (
      <div className="flex flex-1 flex-col gap-6 p-4 lg:p-6">
        <PageHeader
          title="Create vehicle"
          description="Add a new fleet unit to the transport management system."
        />
        <EmptyState
          icon={ShieldAlert}
          title="Permission required"
          description="You do not have permission to create vehicles."
        />
      </div>
    );
  }

  return (
    <div className="flex flex-1 flex-col gap-6 p-4 lg:p-6">
      <PageHeader
        title="Create vehicle"
        description="Add a trailer or jumbo vehicle with validated plate composition."
      />

      <Card>
        <CardContent>
          <CreateVehicleForm
            isSubmitting={mutation.isPending}
            errorMessage={
              mutation.error
                ? getApiErrorMessage(mutation.error, 'Unable to create vehicle.')
                : null
            }
            onSubmit={handleSubmit}
            onCancel={() => router.push(ROUTES.vehicles)}
          />
        </CardContent>
      </Card>
    </div>
  );
}
