'use client';

import { RotateCcw } from 'lucide-react';
import { Button } from '@/components/ui/button';
import type { VehicleStatus, VehicleType } from '../types/vehicle.types';

interface VehicleFiltersProps {
  vehicleType?: VehicleType;
  status?: VehicleStatus;
  availableOnly: boolean;
  onVehicleTypeChange: (value?: VehicleType) => void;
  onStatusChange: (value?: VehicleStatus) => void;
  onAvailableOnlyChange: (value: boolean) => void;
  onReset: () => void;
}

const vehicleTypes: Array<{ value: VehicleType; label: string }> = [
  { value: 'TRAILER', label: 'Trailer' },
  { value: 'JUMBO', label: 'Jumbo' },
];

const statuses: Array<{ value: VehicleStatus; label: string }> = [
  { value: 'ACTIVE', label: 'Active' },
  { value: 'IN_TRIP', label: 'In trip' },
  { value: 'IN_MAINTENANCE', label: 'In maintenance' },
  { value: 'OUT_OF_SERVICE', label: 'Out of service' },
];

export function VehicleFilters({
  vehicleType,
  status,
  availableOnly,
  onVehicleTypeChange,
  onStatusChange,
  onAvailableOnlyChange,
  onReset,
}: VehicleFiltersProps) {
  return (
    <div className="flex flex-wrap items-center gap-2">
      <select
        value={vehicleType ?? ''}
        onChange={(event) =>
          onVehicleTypeChange((event.target.value || undefined) as VehicleType | undefined)
        }
        className="h-8 rounded-lg border border-input bg-background px-2 text-sm text-foreground outline-none transition-colors hover:bg-muted focus:border-ring focus:ring-3 focus:ring-ring/50"
        aria-label="Filter by vehicle type"
      >
        <option value="">All types</option>
        {vehicleTypes.map((item) => (
          <option key={item.value} value={item.value}>
            {item.label}
          </option>
        ))}
      </select>

      <select
        value={status ?? ''}
        onChange={(event) =>
          onStatusChange((event.target.value || undefined) as VehicleStatus | undefined)
        }
        disabled={availableOnly}
        className="h-8 rounded-lg border border-input bg-background px-2 text-sm text-foreground outline-none transition-colors hover:bg-muted focus:border-ring focus:ring-3 focus:ring-ring/50 disabled:cursor-not-allowed disabled:opacity-50"
        aria-label="Filter by status"
      >
        <option value="">All statuses</option>
        {statuses.map((item) => (
          <option key={item.value} value={item.value}>
            {item.label}
          </option>
        ))}
      </select>

      <label className="flex h-8 items-center gap-2 rounded-lg border border-input bg-background px-2 text-sm text-muted-foreground">
        <input
          type="checkbox"
          checked={availableOnly}
          onChange={(event) => onAvailableOnlyChange(event.target.checked)}
          className="size-4 accent-primary"
        />
        Available
      </label>

      <Button
        type="button"
        variant="outline"
        size="icon"
        onClick={onReset}
        aria-label="Reset filters"
      >
        <RotateCcw className="size-4" />
      </Button>
    </div>
  );
}
