import { z } from 'zod';

export const vehicleTypeSchema = z.enum(['TRAILER', 'JUMBO']);
export const vehicleStatusSchema = z.enum([
  'ACTIVE',
  'IN_TRIP',
  'IN_MAINTENANCE',
  'OUT_OF_SERVICE',
]);
export const vehiclePlateRoleSchema = z.enum(['TRUCK_HEAD', 'TRAILER_UNIT', 'JUMBO']);

const optionalTrimmedText = z
  .string()
  .trim()
  .optional()
  .transform((value) => (value ? value : undefined));

export const createVehicleSchema = z
  .object({
    vehicleCode: z.string().trim().min(1, 'Vehicle code is required').max(100),
    type: vehicleTypeSchema,
    status: vehicleStatusSchema.default('ACTIVE'),
    manufacturer: optionalTrimmedText,
    model: optionalTrimmedText,
    productionYear: z.coerce
      .number()
      .int()
      .min(1900)
      .max(2100)
      .optional()
      .or(z.literal('').transform(() => undefined)),
    capacityKg: z.coerce
      .number()
      .int()
      .min(0)
      .optional()
      .or(z.literal('').transform(() => undefined)),
    notes: optionalTrimmedText,
    plates: z.array(
      z.object({
        role: vehiclePlateRoleSchema,
        plateNumber: z.string().trim().min(1, 'Plate number is required').max(50),
      }),
    ),
  })
  .superRefine((value, context) => {
    const roles = value.plates.map((plate) => plate.role);
    const plateNumbers = value.plates.map((plate) => plate.plateNumber.toUpperCase());

    if (new Set(plateNumbers).size !== plateNumbers.length) {
      context.addIssue({
        code: 'custom',
        path: ['plates'],
        message: 'Plate numbers must be unique',
      });
    }

    if (value.type === 'TRAILER') {
      const valid =
        value.plates.length === 2 && roles.includes('TRUCK_HEAD') && roles.includes('TRAILER_UNIT');

      if (!valid) {
        context.addIssue({
          code: 'custom',
          path: ['plates'],
          message: 'Trailer vehicles require one truck head plate and one trailer unit plate',
        });
      }
    }

    if (value.type === 'JUMBO') {
      const valid = value.plates.length === 1 && roles[0] === 'JUMBO';

      if (!valid) {
        context.addIssue({
          code: 'custom',
          path: ['plates'],
          message: 'Jumbo vehicles require one jumbo plate',
        });
      }
    }
  });

export type CreateVehicleFormValues = z.input<typeof createVehicleSchema>;
export type CreateVehicleSubmitValues = z.output<typeof createVehicleSchema>;
