'use client';

import type { ColumnDef } from '@tanstack/react-table';
import { StatusBadge } from '@/components/shared';
import type { Vehicle, VehiclePlateRole } from '../types/vehicle.types';
import { VehicleActionsMenu } from './vehicle-actions-menu';

const plateRoleLabels: Record<VehiclePlateRole, string> = {
  TRUCK_HEAD: 'Head',
  TRAILER_UNIT: 'Trailer',
  JUMBO: 'Jumbo',
};

function formatDate(value: string) {
  return new Intl.DateTimeFormat('en', {
    year: 'numeric',
    month: 'short',
    day: '2-digit',
  }).format(new Date(value));
}

export const vehicleColumns: ColumnDef<Vehicle, unknown>[] = [
  {
    accessorKey: 'vehicleCode',
    header: 'Code',
    cell: ({ row }) => <span className="font-medium">{row.original.vehicleCode}</span>,
  },
  {
    accessorKey: 'type',
    header: 'Type',
    cell: ({ row }) => row.original.type.replace(/_/g, ' '),
  },
  {
    accessorKey: 'status',
    header: 'Status',
    cell: ({ row }) => <StatusBadge status={row.original.status} domain="vehicle" />,
  },
  {
    id: 'plates',
    header: 'Plates',
    cell: ({ row }) => (
      <div className="flex flex-col gap-1">
        {row.original.plates.map((plate) => (
          <span key={plate.id} className="text-xs text-muted-foreground">
            <span className="text-foreground">{plate.plateNumber}</span>{' '}
            {plateRoleLabels[plate.role]}
          </span>
        ))}
      </div>
    ),
  },
  {
    id: 'make',
    header: 'Make',
    cell: ({ row }) => {
      const parts = [row.original.manufacturer, row.original.model].filter(Boolean);
      return parts.length ? parts.join(' ') : <span className="text-muted-foreground">-</span>;
    },
  },
  {
    accessorKey: 'capacityKg',
    header: 'Capacity',
    cell: ({ row }) =>
      row.original.capacityKg ? `${row.original.capacityKg.toLocaleString()} kg` : '-',
  },
  {
    accessorKey: 'createdAt',
    header: 'Created',
    cell: ({ row }) => formatDate(row.original.createdAt),
  },
  {
    id: 'actions',
    header: '',
    cell: () => <VehicleActionsMenu />,
  },
];
